class Robot:
    def __init__(self, name, color, speed):
        self.name = name
        self.color = color
        self.speed = speed
    def move(self):
        print(f'{self.name} is moving at {self.speed} m/s')

r1 = Robot('Namira', 'blue', 5)
r2 = Robot('ASIMO', 'white', 3)
r1.move()  # Namira is moving at 5 m/s

class FlyingRobot(Robot):  # Robot-এর সব feature পাবে
    def __init__(self, name, color, speed, max_altitude):
        super().__init__(name, color, speed)
        self.max_altitude = max_altitude
    def fly(self):
        print(f'{self.name} flying at {self.max_altitude}m')

class Animal:
    def speak(self): pass
class Dog(Animal):
    def speak(self): print('Woof!')
class Cat(Animal):
    def speak(self): print('Meow!') → Polymorphism
